// Point in homogeneous coordinates (x, y, 1)
point P = {x: 3, y: 4, w: 1}

// Translation matrix for (2, 1)
translationMatrix T = [
 [1, 0, 2],
 [0, 1, 1],
 [0, 0, 1]
]

// Apply translation
function transform(matrix M, point p):
 x' = M[0][0]*p.x + M[0][1]*p.y + M[0][2]*p.w
 y' = M[1][0]*p.x + M[1][1]*p.y + M[1][2]*p.w
 w' = M[2][0]*p.x + M[2][1]*p.y + M[2][2]*p.w
 return point(x', y', w')

// Result: P' = (5, 5, 1)

// Rotate point P(5, 5) about pivot (2, 2) by 90°
// Order: Translate to origin → Rotate → Translate back

pivot = (2, 2)
point = (5, 5)
theta = 90 degrees

// Step 1: Translate to move pivot to origin
